#include <iostream>
#include <string>

template <typename T>
T find_maximum(T a, T b) {
    if (a > b) {
        return a;
    } else {
        return b;
    }
}

int main() {
    std::cout << find_maximum(5, 10) << std::endl;
    std::cout << find_maximum(10, 5) << std::endl;
    std::cout << find_maximum(3.14, 2.718) << std::endl;
    std::cout << find_maximum(1.0, 1.000001) << std::endl;
    std::cout << find_maximum(7, 7) << std::endl;
    return 0;
}
